package ccxt

type Mudrex struct {
   *MudrexCore
   Core *MudrexCore
   exchangeTyped *ExchangeTyped
}

func NewMudrex(userConfig map[string]interface{}) *Mudrex {
   p := NewMudrexCore()
   p.Init(userConfig)
   return &Mudrex{
       MudrexCore: p,
       Core:  p,
       exchangeTyped: NewExchangeTyped(&p.Exchange),
   }
}
func NewMudrexFromCore(core *MudrexCore) *Mudrex {
   return &Mudrex{
       MudrexCore: core,
       Core:  core,
       exchangeTyped: NewExchangeTyped(&core.Exchange),
   }
}

